const ACTIVE_PAIRS = ['EUR/USD', 'USD/JPY', 'AUD/JPY', 'USD/CAD'];
const raw = $input.first().json;
const filtered = (raw.signals || []).filter(s =>
  ACTIVE_PAIRS.includes(s.pair) && !['none','error','duplicate'].includes(s.signal)
);
return [{ json: { ...raw, signals: filtered, active_count: filtered.length } }];

const raw = $input.first().json;
if ((raw.active_count || 0) === 0) return [];
return [{ json: raw }];

const raw = $input.first().json;
if ((raw.active_count || 0) > 0) return [];
return [{ json: raw }];

const signals = $input.first().json.signals;
const messages = [];

for (const s of signals) {
  const ai     = s.ai || {};
  const params = s.params || {};
  const emoji  = ai.emoji || '📊';
  const conf   = ai.confidence != null ? `${ai.confidence}%` : '—';
  const quality = ai.quality || '—';
  const risks  = (ai.key_risks || []).map(r => `  • ${r}`).join('\n');
  const rr     = params.rr_ratio || 2.5;
  const direction = s.signal === 'long' ? '🟢 LONG' : '🔴 SHORT';

  const msg = [
    `${emoji} *${s.pair}* — ${direction}`,
    `Strategy: \`${s.strategy}\``,
    ``,
    `Entry:  \`${s.entry}\``,
    `SL:     \`${s.sl}\`  (${params.sl_mult || 2}× ATR)`,
    `TP:     \`${s.tp}\`  (${rr}R)`,
    ``,
    `Indicators: ADX ${s.indicators?.adx} · DI-spread ${s.indicators?.di_spread} · RSI ${s.indicators?.rsi}`,
    `Params: ADX≥${params.adx_min} · DI-spread≥${params.di_spread_min}`,
    ``,
    `AI Confidence: *${conf}* (${quality})`,
    ai.summary ? `💬 ${ai.summary}` : '',
    risks ? `\n⚠️ Risks:\n${risks}` : '',
    ``,
    `📅 Bar: ${s.bar_time} SAST`,
    `🤖 Signal Engine · Optimized`,
  ].filter(Boolean).join('\n');

  messages.push({ json: { text: msg, pair: s.pair, signal: s.signal } });
}

return messages;

const raw = $input.first().json;
const snapshot = raw.market_snapshot || [];

const lines = snapshot.map(s => {
  if (s.signal === 'error') {
    return `  *${s.pair}*  ⚠️ Data feed error`;
  }
  const ind = s.indicators || {};
  const adx = ind.adx != null ? Number(ind.adx).toFixed(1) : '—';
  const rsi = ind.rsi != null ? Number(ind.rsi).toFixed(1) : '—';
  const diSpread = ind.di_spread != null ? Number(ind.di_spread).toFixed(1) : '—';
  const trend = ind.adx >= 35 ? '🔥 Strong' : ind.adx >= 25 ? '📈 Moderate' : '😴 Weak';
  const status = s.signal === 'duplicate' ? '🔁 Duplicate' : '⏸ No entry';
  return `  *${s.pair}*  ADX ${adx} · RSI ${rsi} · DI-spread ${diSpread} · ${trend} · ${status}`;
});

const generated = raw.generated ? raw.generated.replace('T', ' ').slice(0, 19) : '';

const text = [
  '📊 *SignalEdge — Market Scan Complete*',
  '',
  '_No trade setups met entry criteria this hour._',
  '',
  '*Pair Snapshot:*',
  ...lines,
  '',
  `📅 ${generated} SAST`,
  '🤖 Signal Engine · Optimized',
].join('\n');

return [{ json: { text, pair: 'ALL', signal: 'none' } }];

const raw = $input.first().json;
const errors = raw.errors || [];
if (errors.length === 0) return [];
return [{ json: raw }];

const raw = $input.first().json;
const errors = raw.errors || [];
let lines;
if (errors.length > 0) {
  lines = errors.map(e => `  • ${e.pair}: ${e.error || 'unknown error'}`);
} else {
  lines = [`  • API unreachable: ${raw.message || raw.error || 'connection failed'}`];
}
const sast = new Date().toLocaleString('en-ZA', { timeZone: 'Africa/Johannesburg', hour12: false }).replace(',', '');
const text = `⚠️ *SignalEdge API Error*\n\nThe signal engine could not be reached:\n${lines.join('\n')}\n\n📅 ${sast} SAST`;
return [{ json: { text } }];
